import java.util.Arrays;
import java.util.Scanner;
public class Main {
static class Edge implements Comparable<Edge> { int w, u, v;
public Edge(int w, int u, int v) { this.w = w; this.u = u; this.v = v; }
@Override
public int compareTo(Edge o) { return this.w - o.w; }}
public static int find(int[] parent, int i) { if (parent[i] == i) return i; return find(parent, parent[i]); }
public static void unionSet(int[] parent, int[] rank, int x, int y) { int xroot = find(parent, x), yroot = find(parent, y);
if (rank[xroot] < rank[yroot]) parent[xroot] = yroot;
else if (rank[xroot] > rank[yroot]) parent[yroot] = xroot;
else { parent[yroot] = xroot; rank[xroot]++; }}
public static void main(String[] args) {
Scanner scanner = new Scanner(System.in);
int n = scanner.nextInt();
int m = scanner.nextInt();
int[] parent = new int[n];
int[] rank = new int[n];
for (int i = 0; i < n; i++) { parent[i] = i; rank[i] = 0; }
Edge[] edges = new Edge[m];
for (int i = 0; i < m; i++) {
int u = scanner.nextInt() - 1;
int v = scanner.nextInt() - 1;
int w = scanner.nextInt();
edges[i] = new Edge(w, u, v);
}
Arrays.sort(edges);
long result = 0;
for (int i = 0; i < m; i++) {
if (find(parent, edges[i].u) != find(parent, edges[i].v)) {
result += edges[i].w;
unionSet(parent, rank, edges[i].u, edges[i].v);
}
}
System.out.println(result);
}
}

